154→describe("isSimilarTitle", () => {
155→  it("returns true for identical titles", () => {
156→    const title = "feat: Add new ToolSearch capability";
157→    expect(isSimilarTitle(title, title)).toBe(true);
158→  });
159→
160→  it("returns true for titles with same content different format", () => {
161→    const title1 = "feat: Add ToolSearch capability";
162→    const title2 = "Add ToolSearch capability v2.1.29";
163→    expect(isSimilarTitle(title1, title2)).toBe(true);
164→  });
165→
166→  it("returns false for completely different titles", () => {
167→    const title1 = "feat: Add new hook system";
168→    const title2 = "fix: Resolve permission error";
169→    expect(isSimilarTitle(title1, title2)).toBe(false);
170→  });
171→
172→  it("handles version differences in similar titles", () => {
173→    const title1 = "New tool: ToolSearch in v2.1.29";
174→    const title2 = "New tool: ToolSearch in v2.1.30";
175→    expect(isSimilarTitle(title1, title2)).toBe(true);
176→  });
177→
178→  it("returns false for empty titles", () => {
179→    expect(isSimilarTitle("", "")).toBe(false);
180→  });
181→
182→  it("handles partial overlap correctly", () => {
183→    const title1 = "Add new feature for task handling";
184→    const title2 = "Add new feature for hook handling";
185→    // Both share "add", "new", "feature", "handling" but differ on "task" vs "hook"
186→    const similar = isSimilarTitle(title1, title2);
187→    // 4/5 overlap = 80% > 60% threshold
188→    expect(similar).toBe(true);
189→  });
190→
191→  it("returns false when overlap is below threshold", () => {
192→    const title1 = "alpha beta gamma delta epsilon";
193→    const title2 = "zeta eta theta iota kappa";
194→    expect(isSimilarTitle(title1, title2)).toBe(false);
195→  });
196→});
